css:
.lang-container {
      position: fixed;
      bottom: 24px;
      left: 24px;
      z-index: 999;
    }
    .lang-btn {
      display: flex;
      align-items: center;
      gap: 6px;
      font-family: inherit;
      font-size: 0.65rem;
      font-weight: 600;
      text-transform: uppercase;
      letter-spacing: 0.12em;
      padding: 10px 16px;
      border-radius: 9999px;
      box-shadow: 0 4px 12px rgba(15,28,53,0.1);
      background: var(--ivory);
      color: var(--carbon);
      border: 1px solid rgba(15,28,53,0.12);
      cursor: pointer;
      transition: all 0.25s ease;
    }
    .lang-btn:hover {
      transform: translateY(-2px);
      border-color: var(--gold);
      color: #94752a;
      box-shadow: 0 6px 16px rgba(15,28,53,0.15);
    }
